/**
 * @summary List calculations
 */
export const getListCalculationsUrl = (params?: ListCalculationsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/calculations?${stringifiedParams}`
    : `/api/calculations`;
};

export const listCalculations = async (
  params?: ListCalculationsParams,
  options?: RequestInit,
): Promise<Calculation[]> => {
  return customFetch<Calculation[]>(getListCalculationsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListCalculationsQueryKey = (
  params?: ListCalculationsParams,
) => {
  return [`/api/calculations`, ...(params ? [params] : [])] as const;
};

export const getListCalculationsQueryOptions = <
  TData = Awaited<ReturnType<typeof listCalculations>>,
  TError = ErrorType<unknown>,
>(
  params?: ListCalculationsParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listCalculations>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getListCalculationsQueryKey(params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof listCalculations>>
  > = ({ signal }) => listCalculations(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listCalculations>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

